const now = new Date();
const h = String(now.getUTCHours()).padStart(2, '0');
const m = String(now.getUTCMinutes()).padStart(2, '0');
const checkTime = `${h}:${m}:00`;

// Only run between 06:00 and 12:00 UTC
const hour = now.getUTCHours();
if (hour < 6 || hour > 12) {
  console.log('Outside morning window, skipping');
  return [];
}

console.log('Checking for morning reflections at:', checkTime);
return [{ json: { checkTime } }];

const items = $input.first().json;
const prefs = Array.isArray(items) ? items : [items];

if (!prefs || prefs.length === 0 || !prefs[0].id) {
  console.log('No matching preferences found');
  return [];
}

// Filter to Full Programme only
const fullProgramme = prefs.filter(p => p.child_profiles?.mode === 'full_programme');
console.log(`Found ${fullProgramme.length} Full Programme preference(s)`);

return fullProgramme.map(p => ({ json: p }));

// Check for last night's session (5pm yesterday to midnight)
const pref = $input.item.json;
const childId = pref.child_id;

const now = new Date();
const yesterday5pm = new Date(now);
yesterday5pm.setDate(now.getDate() - 1);
yesterday5pm.setHours(17, 0, 0, 0);

const todayMidnight = new Date(now);
todayMidnight.setHours(0, 0, 0, 0);

return [{
  json: {
    ...pref,
    yesterdayFrom: yesterday5pm.toISOString(),
    todayMidnight: todayMidnight.toISOString()
  }
}];

const sessions = $input.first().json;
const sessionArr = Array.isArray(sessions) ? sessions : [];

if (sessionArr.length === 0) {
  console.log('No session last night for child:', $('Calculate Date Range').item.json.child_id, '— skipping');
  return [];
}

const session = sessionArr[0];
console.log('Found last night session:', session.id);

return [{ json: { lastSession: session } }];

const pref = $('Calculate Date Range').item.json;
const profile = pref.child_profiles;
const session = $('Check Session Exists').first().json.lastSession;
const historyRaw = $('Fetch Session History').first().json;
const history = Array.isArray(historyRaw) ? historyRaw : [];
const ctxRaw = $('Fetch Dynamic Context').first().json;
const ctx = Array.isArray(ctxRaw) ? ctxRaw[0] || {} : ctxRaw || {};

const systemPrompt = `You are a warm, perceptive child development observer helping a parent notice what is happening in their child's emotional world through bedtime stories. You have access to the child's profile and their recent story sessions. Your job is to generate exactly three observations the parent can react to the following morning.

OBSERVATION RULES:
- Each observation must be specific to this child — never generic
- Each observation must interpret, not just describe
- Each observation must pass this test: would the parent have noticed and named this themselves? If yes, replace it
- Use warm, plain language — not clinical terms
- Maximum 2 sentences per observation
- Three types: story observation, behaviour observation, pattern observation. Use all three where possible.
- Pattern observations only if 4+ nights of data exist
- Never mention the app, the study, or therapeutic frameworks
- Never diagnose. Observe and reflect only.
- End each observation with something the parent can notice or do today

OUTPUT FORMAT — return valid JSON only:
{
  "observations": [
    { "type": "story", "text": "..." },
    { "type": "behaviour", "text": "..." },
    { "type": "pattern", "text": "..." }
  ]
}`;

const historyText = history.length > 1
  ? history.slice().reverse().map((s, i) =>
    `Night ${i + 1}: prompt="${s.story_prompt || 'none'}", themes=${(s.themes || []).join(',') || 'none'}`
  ).join('\n')
  : 'First night — no history yet';

const userPrompt = `CHILD PROFILE:
Name: ${profile.name}, Age: ${profile.age}
Personality: ${profile.personality_description || 'Not provided'}
Neuro flags: ${(profile.neuro_flags || []).join(', ') || 'None'}
Fear flags: ${(ctx.fear_flags || []).join(', ') || 'None'}
Current stressors: ${ctx.current_stressors || 'None noted'}
Allies: ${(ctx.allies || []).filter(a => a.name).map(a => a.name + (a.relationship ? ' (' + a.relationship + ')' : '')).join(', ') || 'None'}

LAST NIGHT:
Date: ${session.created_at}
Mode: ${session.mode || 'co-creation'}
Story prompt (child's words): ${session.story_prompt || 'None'}
Parent note: ${session.parent_note || 'None'}
Story themes: ${(session.themes || []).join(', ') || 'Not tagged'}
Villain appeared: ${session.villain_appeared ?? 'Unknown'}

RECENT HISTORY (last 6 nights, oldest first):
${historyText}

Generate three observations now.`;

console.log('Built Claude prompt for:', profile.name);

return [{
  json: {
    claudePayload: {
      model: 'claude-sonnet-4-6-20250514',
      max_tokens: 1024,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }]
    },
    sessionId: session.id,
    childId: pref.child_id,
    userId: pref.user_id,
    childName: profile.name,
    subscription: pref.push_subscription,
    storyPrompt: session.story_prompt
  }
}];

const response = $input.first().json;
let content = '';

if (response.content && response.content[0]) {
  content = response.content[0].text;
} else {
  throw new Error('Unexpected Claude response format: ' + JSON.stringify(response).substring(0, 200));
}

// Clean and parse JSON
const cleaned = content.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse Claude response: ${e.message}. Content: ${cleaned.substring(0, 300)}`);
}

if (!parsed.observations || parsed.observations.length !== 3) {
  throw new Error(`Expected 3 observations, got ${parsed.observations?.length || 0}`);
}

console.log('Claude returned 3 observations');

return [{ json: { observations: parsed.observations } }];

const data = $('Build Claude Prompt').first().json;
const childName = data.childName;
const storyPrompt = data.storyPrompt;

let body;
if (storyPrompt) {
  const summary = storyPrompt.length > 40 ? storyPrompt.substring(0, 40) + '...' : storyPrompt;
  body = `${childName} wanted "${summary}" last night — we noticed something. Tap to see.`;
} else {
  body = `We have three things to share from ${childName}'s night. Tap to see.`;
}

return [{
  json: {
    subscription: data.subscription,
    payload: {
      title: 'DreamStation',
      body: body,
      tag: 'morning-reflection',
      url: '/?morning=true'
    }
  }
}];
